import click
from uuid_utils.compat import UUID

from typeid import TypeID
from typeid import base32
from typeid import from_uuid
from typeid import get_prefix_and_suffix


@click.group()
def cli():
    pass


@cli.command()
@click.option("-p", "--prefix")
def new(prefix: str | None = None) -> None:
    typeid = TypeID(prefix=prefix)
    click.echo(str(typeid))


@cli.command()
@click.argument("uuid")
@click.option("-p", "--prefix")
def encode(uuid: str, prefix: str | None = None) -> None:
    typeid = from_uuid(suffix=UUID(uuid), prefix=prefix)
    click.echo(str(typeid))


@cli.command()
@click.argument("encoded")
def decode(encoded: str) -> None:
    prefix, suffix = get_prefix_and_suffix(encoded)

    decoded_bytes = bytes(base32.decode(suffix))
    uuid = UUID(bytes=decoded_bytes)

    click.echo(f"type: {prefix}")
    click.echo(f"uuid: {uuid}")


if __name__ == "__main__":
    cli()

import pytest
import uuid_utils.compat as uuid

from typeid import base32
from typeid.errors import PrefixValidationException
from typeid.errors import SuffixValidationException
from typeid.validation import validate_prefix
from typeid.validation import validate_suffix


def test_validate_correct_prefix() -> None:
    prefix = "plov"

    try:
        validate_prefix(prefix)
    except PrefixValidationException as exc:
        pytest.fail(str(exc))


def test_validate_correct_prefix_with_underscores() -> None:
    prefix = "plov_good"

    try:
        validate_prefix(prefix)
    except PrefixValidationException as exc:
        pytest.fail(str(exc))


def test_validate_invalid_prefix_with_trailing_underscore() -> None:
    prefix = "plov_bad_"

